import { useState } from "react";
import { useForm } from "react-hook-form";
import { addRepaymentPlan } from "../services/debtService";
import { Modal } from "bootstrap";

const RepaymentPlan = ({ debtId }) => {

  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("");

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors }
  } = useForm();

  const onSubmit = async (data) => {
  
    const request = {
    id: 0,
    debtId: debtId,
    monthlyPaymentAmount: parseFloat(data.monthlyPaymentAmount),
    dateStarted: data.dateStarted
  };

  try {
    const result = await addRepaymentPlan(request);

    if (result > 0) {

      setMessage("Payment plan added successfully");
      setMessageType("success");

      // reset form
      reset();

        setTimeout(() => {

        setMessage("");

        onClose();
      

      }, 1500);

    } else {
      setMessage("Failed to add payment plan");
      setMessageType("danger");
    }

  } catch (err) {
      setMessage("Error calling API");
      setMessageType("danger");
  }
};


  return (
    <div
      className="modal fade"
      id="repaymentModal"
      tabIndex="-1"
      aria-hidden="true"
    >
      <div className="modal-dialog">
        <div className="modal-content">

          {/* Header */}
          <div className="modal-header">
            <h5 className="modal-title">Add Repayment Plan</h5>

            <button
              type="button"
                className="btn-close"
                onClick={onClose}
            />
          </div>

          {/* Body */}
          <div className="modal-body">

            {message && (
              <div className={`alert alert-${messageType}`}>
                {message}
              </div>
            )}

            <form onSubmit={handleSubmit(onSubmit)}>

              {/* Monthly Payment */}
              <div className="mb-3">
                <label className="form-label">Monthly Payment Amount</label>

                <input
                  type="number"
                  className="form-control"
                  {...register("monthlyPaymentAmount", {
                    required: "Monthly payment amount is required",
                    min: {
                      value: 1,
                      message: "Amount must be greater than 0"
                    }
                  })}
                />

                {errors.monthlyPaymentAmount && (
                  <small className="text-danger">
                    {errors.monthlyPaymentAmount.message}
                  </small>
                )}
              </div>

              {/* Date Started */}
              <div className="mb-3">
                <label className="form-label">Date Started</label>

                <input
                  type="date"
                  className="form-control"
                  {...register("dateStarted", {
                    required: "Start date is required"
                  })}
                />

                {errors.dateStarted && (
                  <small className="text-danger">
                    {errors.dateStarted.message}
                  </small>
                )}
              </div>

              {/* Buttons */}
              <div className="modal-footer px-0 pb-0">
                <button
                    type="submit"
                    className="btn btn-primary"
                  >
                    Add
                  </button>

                <button
                  type="button"
                    className="btn btn-secondary"
                    onClick={onClose}
                >
                  Close
                </button>

             
              </div>

            </form>
          </div>

        </div>
      </div>
    </div>
  );
};

export default RepaymentPlan;
